/* SearchWP Live Ajax Search — simplified client */
(function($){
if(typeof $==='undefined'||!$.fn)return;
var params=typeof searchwp_live_search_params!=='undefined'?searchwp_live_search_params:{};
var cfg=params&&params.config?params.config:{};
var defaults=cfg.default||{};
if(!defaults.engine)return;
var $input=$('.site-search__input[data-swplive="true"]');
if(!$input.length)return;
var parent=defaults.parent_el||'.site-search-results';
var $parent=$(parent);
var min=defaults.input&&defaults.input.min_chars?defaults.input.min_chars:3;
var delay=defaults.input&&defaults.input.delay?defaults.input.delay:400;
var timer=null;
function doSearch(term){
  $parent.html('<div class="site-search-results-wrapper"><p style="padding:2rem;color:#666;font-size:1.4rem">Recherche locale non disponible. Le site d\'origine utilise un backend WordPress.</p></div>');
}
$input.on('input',function(){
  var val=$(this).val().trim();
  clearTimeout(timer);
  if(val.length<min){$parent.empty();return;}
  timer=setTimeout(function(){doSearch(val);},delay);
});
$input.on('focus',function(){
  var val=$(this).val().trim();
  if(val.length>=min)doSearch(val);
});
})(window.jQuery);
